// LRU Replacement for Set-Associative Cache
SETS = 256
WAYS = 4
BLOCK_SIZE = 64

cache = array[SETS][WAYS] of {valid, tag, data, last_used}
global_counter = 0

function access_set_associative(address):
 set_index = extract_index(address)
 tag = extract_tag(address)

 // Check all ways in the set
 for way = 0 to WAYS-1:
 if cache[set_index][way].valid AND cache[set_index][way].tag == tag:
 // Hit - update LRU counter
 cache[set_index][way].last_used = global_counter
 global_counter = global_counter + 1
 return cache[set_index][way].data

 // Miss - find LRU way to replace
 lru_way = find_min_lru(set_index)
 load_block_from_memory(address, cache[set_index][lru_way])
 cache[set_index][lru_way].last_used = global_counter
 global_counter = global_counter + 1
 return cache[set_index][lru_way].data

function find_min_lru(set_index):
 min_lru = cache[set_index][0].last_used
 min_way = 0
 for way = 1 to WAYS-1:
 if cache[set_index][way].last_used < min_lru:
 min_lru = cache[set_index][way].last_used
 min_way = way
 return min_way
